import java.util.PriorityQueue;
import java.util.Comparator;

public class Solution {
    // Helper class/record for Priority Queue elements
    static class State {
        long time;
        long color;
        int r;
        int c;

        public State(long time, long color, int r, int c) {
            this.time = time;
            this.color = color;
            this.r = r;
            this.c = c;
        }
    }

    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // TimeGrid stores the minimum time to reach (r, c). Initialize to infinity.
        // Max possible time is N*M, so N*M + 1 is safe for infinity.
        long INF_TIME = (long) N * M + 1;
        long[][] timeGrid = new long[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                timeGrid[i][j] = INF_TIME;
            }
        }

        // ColorGrid stores the final color. Initialize to 0 (uncolored).
        long[][] colorGrid = new long[N][M];

        // Priority Queue: Prioritize lower time, then higher color.
        PriorityQueue<State> pq = new PriorityQueue<>(
            Comparator.comparingLong((State s) -> s.time) // Primary sort: minimum time
                      .thenComparingLong(s -> -s.color)   // Secondary sort: maximum color (minimize negative color)
        );

        // 1. Initialization from sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            long color = source[2];

            // Since multiple sources might start at the same location (though problem states they are unique), 
            // we ensure the best starting condition is recorded.
            if (color > colorGrid[r][c]) {
                timeGrid[r][c] = 0;
                colorGrid[r][c] = color;
                pq.add(new State(0, color, r, c));
            }
        }

        int[] dr = {0, 0, 1, -1};
        int[] dc = {1, -1, 0, 0};

        // 2. Dijkstra-like expansion
        while (!pq.isEmpty()) {
            State current = pq.poll();
            long t = current.time;
            long c = current.color;
            int r = current.r;
            int c_idx = current.c;

            // Check for stale entries (if we found a better path to (r, c) already)
            // Note: Because of how we populate the PQ, we must check both time and color against the stored state.
            if (t > timeGrid[r][c_idx] || (t == timeGrid[r][c_idx] && c < colorGrid[r][c_idx])) {
                continue;
            }

            // Explore neighbors
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c_idx + dc[i];

                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    long nextTime = t + 1;
                    long nextColor = c;

                    long currentBestTime = timeGrid[nr][nc];
                    long currentBestColor = colorGrid[nr][nc];

                    // Check for improvement:
                    // 1. Faster arrival (nextTime < currentBestTime)
                    // 2. Same arrival time but better color (nextTime == currentBestTime AND nextColor > currentBestColor)
                    if (nextTime < currentBestTime || 
                        (nextTime == currentBestTime && nextColor > currentBestColor)) {

                        // Update grid state
                        timeGrid[nr][nc] = nextTime;
                        colorGrid[nr][nc] = nextColor;

                        // Push new state to PQ
                        pq.add(new State(nextTime, nextColor, nr, nc));
                    }
                }
            }
        }

        return colorGrid;
    }
}

