import java.util.PriorityQueue;
import java.util.Comparator;

public class Solution {

    // Helper class to represent a state in the priority queue
    static class State {
        long time;
        long color;
        int r;
        int c;

        public State(long time, long color, int r, int c) {
            this.time = time;
            this.color = color;
            this.r = r;
            this.c = c;
        }
    }

    // Helper class to store the best known state for a cell
    static class CellState {
        long time;
        long color;

        public CellState() {
            this.time = Long.MAX_VALUE;
            this.color = 0;
        }

        public CellState(long time, long color) {
            this.time = time;
            this.color = color;
        }
    }

    /**
     * Solves the grid coloring propagation problem using Dijkstra's algorithm 
     * with custom priority queue ordering for time and color tie-breaking.
     */
    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // Distance/State array: stores the minimum time and the winning color for each cell
        CellState[][] dist = new CellState[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dist[i][j] = new CellState();
            }
        }

        // Custom Comparator for Min-Heap: Prioritize smaller time, then larger color.
        Comparator<State> stateComparator = (s1, s2) -> {
            // 1. Compare time (Min-Heap behavior for time)
            if (s1.time != s2.time) {
                return Long.compare(s1.time, s2.time);
            }
            // 2. Compare color (Max-Heap behavior for color when times are equal)
            return Long.compare(s2.color, s1.color);
        };

        PriorityQueue<State> pq = new PriorityQueue<>(stateComparator);

        // Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            long color = source[2];

            // Since sources are guaranteed unique, we initialize directly
            if (dist[r][c].time > 0) {
                dist[r][c].time = 0;
                dist[r][c].color = color;
                pq.offer(new State(0, color, r, c));
            }
        }

        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        // Dijkstra's algorithm execution
        while (!pq.isEmpty()) {
            State current = pq.poll();
            long T = current.time;
            long C = current.color;
            int r = current.r;
            int c = current.c;

            // Stale entry check: If we found a better path previously, skip this old entry.
            // We check if the extracted state is worse than the recorded best state.
            // Since the PQ handles priority, we only need to check if the current recorded state
            // is strictly better than what we extracted (or equal, but if equal, we proceed 
            // only if it matches the currently stored best state).
            if (T > dist[r][c].time || (T == dist[r][c].time && C < dist[r][c].color)) {
                continue;
            }

            // Optimization: If the current state matches the stored best state, proceed.
            // If we extracted (T, C), and D[r][c] is (T_old, C_old), and T=T_old and C=C_old, we proceed.

            // Explore neighbors
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    long T_new = T + 1;
                    long C_new = C;

                    CellState oldState = dist[nr][nc];

                    // Check if the new state (T_new, C_new) is strictly better than the old state (oldState.time, oldState.color)
                    boolean isBetter = false;
                    if (T_new < oldState.time) {
                        // Case 1: Reaching it strictly sooner
                        isBetter = true;
                    } else if (T_new == oldState.time) {
                        // Case 2: Reaching at the same time, check color
                        if (C_new > oldState.color) {
                            isBetter = true;
                        }
                    }

                    if (isBetter) {
                        dist[nr][nc].time = T_new;
                        dist[nr][nc].color = C_new;
                        pq.offer(new State(T_new, C_new, nr, nc));
                    }
                }
            }
        }

        // Construct the result matrix
        long[][] result = new long[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                // The final color is stored in dist[i][j].color
                // If time is MAX_VALUE, it means it was never reached, color remains 0, which is correct.
                result[i][j] = dist[i][j].color;
            }
        }

        return result;
    }
}

