public class Solution {
    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // Time[r][c]: Minimum time to reach (r, c). Initialize to infinity.
        int[][] timeGrid = new int[N][M];
        // Color[r][c]: Final color determined for (r, c).
        int[][] colorGrid = new int[N][M];

        final int INF = Integer.MAX_VALUE;

        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                timeGrid[i][j] = INF;
                colorGrid[i][j] = 0;
            }
        }

        // Priority Queue stores states (time, r, c), prioritized by minimum time.
        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingInt(s -> s.time));

        // Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            // Since sources are guaranteed to have distinct coordinates, 
            // we just set the initial state.
            if (timeGrid[r][c] > 0) {
                timeGrid[r][c] = 0;
                colorGrid[r][c] = color;
                pq.add(new State(r, c, 0));
            }
        }

        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        // Multi-source BFS / Dijkstra
