            State current = pq.poll();
            long t_curr = current.time;
            int r_curr = current.r;
            int c_curr = current.c;

            // Optimization check: If we extracted a state that is worse than the current known best state, skip it.
            // This handles stale entries in the PQ due to subsequent color updates.
            // We check based on time first.
            if (t_curr > T[r_curr][c_curr]) {
                continue;
            }

            // Use the definitive color for the current cell at the finalized time T[r_curr][c_curr]
            // This ensures propagation uses the maximum color found so far for this shortest time.
            long c_curr_final = C[r_curr][c_curr];

            // Explore neighbors
            for (int i = 0; i < 4; i++) {
